# 提取SVG内容
if data_url.startswith("data:image/svg+xml,"):
    # 解码URL编码
    svg_content = urllib.parse.unquote(data_url.split(",")[1])

    # 创建目录
    if not os.path.exists(directory):
        os.makedirs(directory)
        print(f"目录 '{directory}' 已创建。")
    
    # 创建SVG文件并写入内容
    svg_file_path = os.path.join(directory, svg_file_name)

    with open(svg_file_path, 'w', encoding='utf-8') as svg_file:
        svg_file.write(svg_content)

    print(f"SVG文件 '{svg_file_name}' 已创建，路径为：{svg_file_path}")
else:
    print("提供的字符串不是有效的SVG数据URL。")
